"use client";

import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { useState, useEffect } from "react";
import { Rocket, Sparkles } from "lucide-react";

export function CosmicTrigger() {
  const [isVisible, setIsVisible] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  useEffect(() => {
    // Delay appearance for a smooth entrance
    const timer = setTimeout(() => setIsVisible(true), 2000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 0, scale: 0, y: 100 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0, y: 100 }}
          transition={{ type: "spring", stiffness: 260, damping: 20 }}
          className="fixed bottom-8 right-8 z-50"
        >
          <Link href="/solar-quest">
            <motion.div
              className="relative group cursor-pointer"
              onMouseEnter={() => setIsHovered(true)}
              onMouseLeave={() => setIsHovered(false)}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
            >
              {/* Orbital Rings */}
              <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-4 border border-dashed border-accent/30 rounded-full w-24 h-24"
              />
              <motion.div
                animate={{ rotate: -360 }}
                transition={{ duration: 15, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-2 border border-dotted border-white/20 rounded-full w-20 h-20"
              />

              {/* Core Planet Button */}
              <div className="w-16 h-16 rounded-full bg-gradient-to-br from-indigo-900 via-purple-900 to-black border-2 border-accent/50 shadow-[0_0_30px_rgba(124,58,237,0.5)] flex items-center justify-center overflow-hidden relative">
                {/* Atmosphere Glow */}
                <div className="absolute inset-0 bg-accent/20 blur-md rounded-full animate-pulse" />
                
                {/* Icon */}
                <div className="relative z-10 text-white">
                  <Rocket className={`w-8 h-8 transition-transform duration-500 ${isHovered ? "-translate-y-1 translate-x-1" : "translate-y-0"}`} />
                </div>

                {/* Star sparkles */}
                <motion.div
                  animate={{ opacity: [0, 1, 0] }}
                  transition={{ duration: 2, repeat: Infinity }}
                  className="absolute top-2 right-3"
                >
                  <Sparkles className="w-3 h-3 text-yellow-200" />
                </motion.div>
              </div>

              {/* Tooltip */}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: isHovered ? 1 : 0, x: isHovered ? -10 : -20 }}
                className="absolute right-full top-1/2 -translate-y-1/2 mr-4 whitespace-nowrap bg-black/80 backdrop-blur-md border border-white/10 px-4 py-2 rounded-xl text-xs font-mono text-accent pointer-events-none"
              >
                <span className="flex items-center gap-2">
                  <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                  INITIATE SOLAR QUEST
                </span>
              </motion.div>
            </motion.div>
          </Link>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
